def prep_rcg1(): ifs_data = case_id.sudo().kv_store().get("ifs_data") tipologia_risoluzione = ifs_data.get("tipologia_risoluzione") message = shared_data() is_person = not case_id.customer_id.is_company is_ui = message["TIPOLOGIA_RISOLUZIONE"] != "CA4" service_point = case_id.service_point_ids[0] invoicing_address = service_point.billing_profile_id.invoicing_address_id message.update( { "COD_SERVIZIO": "RCG1", "COD_PDR": case_id.service_point_ids[0].pdr_id.code, "MOTIVAZIONE": "Scelta commerciale Sorgenia", "PRIORITA": "", "ALTRE_INFORMAZIONI": "", "NOME": _not_cae1_ca1( case_id.customer_id.firstname if is_person else "", tipologia_risoluzione, ), "COGNOME": _not_cae1_ca1( case_id.customer_id.lastname if is_person else "", tipologia_risoluzione ), "EMAIL": _not_cae1_ca1( case_id.customer_id.email or "", tipologia_risoluzione ), "TELEFONO": _not_cae1_ca1( case_id.customer_id.phone or "", tipologia_risoluzione ), "ACCESSO_FUI": _not_cae1_ca1( "SI" if message["TIPOLOGIA_RISOLUZIONE"] == "CA4" else "NO", tipologia_risoluzione, ), "UI_CF": _not_cae1_ca1( case_id.customer_id.fiscal_code if is_ui else "", tipologia_risoluzione ), "UI_PIVA": _not_cae1_ca1( case_id.customer_id.vat if is_ui else "", tipologia_risoluzione ), "UI_CF_STRANIERO": _not_cae1_ca1("", tipologia_risoluzione), "UI_NOME": _not_cae1_ca1( case_id.customer_id.firstname if is_ui and is_person else "", tipologia_risoluzione, ), "UI_COGNOME": _not_cae1_ca1( case_id.customer_id.lastname if is_ui and is_person else "", tipologia_risoluzione, ), "UI_RAGIONE_SOCIALE_DENOMINAZIONE": _not_cae1_ca1( case_id.customer_id.name if is_ui and not is_person else "", tipologia_risoluzione, ), "UI_EMAIL": _not_cae1_ca1( case_id.customer_id.email or "" if is_ui else "", tipologia_risoluzione ), "UI_TELEFONO": _not_cae1_ca1( case_id.customer_id.phone or "" if is_ui else "", tipologia_risoluzione ), "UI_AF_CF": _not_cae1_ca1("", tipologia_risoluzione), "UI_AF_PIVA": _not_cae1_ca1("", tipologia_risoluzione), "UI_AF_CF_STRANIERO": _not_cae1_ca1("", tipologia_risoluzione), "UI_AF_NOME": _not_cae1_ca1("", tipologia_risoluzione), "UI_AF_COGNOME": _not_cae1_ca1("", tipologia_risoluzione), "UI_AF_RAGIONE_SOCIALE_DENOMINAZIONE": _not_cae1_ca1( "", tipologia_risoluzione ), "UI_FOR_TOPONIMO": _not_cae1_ca1( service_point.service_toponym_id.name or "", tipologia_risoluzione ), "UI_FOR_VIA": _not_cae1_ca1( service_point.service_street or "", tipologia_risoluzione ), "UI_FOR_CIV": _not_cae1_ca1( service_point.service_street_number or "", tipologia_risoluzione ), "UI_FOR_CAP": _not_cae1_ca1( service_point.service_zip or "40100", tipologia_risoluzione ), "UI_FOR_ISTAT": _not_cae1_ca1( service_point.service_city_id.istat_code or "", tipologia_risoluzione ), "UI_FOR_LOCALITA": _not_cae1_ca1( service_point.service_city_id.name or "", tipologia_risoluzione ), "UI_FOR_PROV": _not_cae1_ca1( service_point.service_state_code or "", tipologia_risoluzione ), "UI_FOR_NAZIONE": ( _not_cae1_ca1( service_point.service_country_id.with_context( lang="it_IT" ).name.upper(), tipologia_risoluzione, ) ) or "", "UI_FOR_ALTRO": "", "UI_ES_TOPONIMO": _not_cae1_ca1( invoicing_address.toponym_id.name or "", tipologia_risoluzione ), "UI_ES_VIA": _not_cae1_ca1( invoicing_address.street or "", tipologia_risoluzione ), "UI_ES_CIV": _not_cae1_ca1( invoicing_address.street_num or "", tipologia_risoluzione ), "UI_ES_CAP": _not_cae1_ca1( invoicing_address.zip or "", tipologia_risoluzione ), "UI_ES_ISTAT": _not_cae1_ca1( invoicing_address.istat_code or "", tipologia_risoluzione ), "UI_ES_LOCALITA": _not_cae1_ca1( invoicing_address.city_id.name or "", tipologia_risoluzione ), "UI_ES_PROV": _not_cae1_ca1( invoicing_address.state_code or "", tipologia_risoluzione ), "UI_ES_NAZIONE": _not_cae1_ca1( invoicing_address.country_id.with_context(lang="it_IT").name.upper() or "", tipologia_risoluzione, ), "UI_ES_ALTRO": _not_cae1_ca1("", tipologia_risoluzione), "UI_CODICE_UFFICIO": service_point.billing_profile_id.office_code or "", "UI_PAGAMENTO_