def create_order_disconnect(asset_id, token): url = "http://b2w-cpq-order-management-service/v1/order" headers = { "X-Auth-Request-Access-Token": "" + token, "Content-Type": "application/json", "generatesession": "true", } body = { "obj_type": "Order", "crm_accountcode": case_id.customer_id.user_sequence, "accountcode": str(case_id.customer_id.id), "type": "Disconnect", "subtype": case_id.ticket_type_id.name, "industry": "BSP Utility", "commodity": "power" if case_id.service_point_ids[0].pod_id else "gas", "order_date": case_id.disconnect_date.strftime("%Y-%m-%d"), "contract": True, "singlecontract": True, "assets": [asset_id], "options": { "userLanguage": "en-US", "remotePagination": True, "itemsForPage": 10, "cartItemsForPage": 10, }, }
logs.append({"message": "Creating order", "data": {"body": body}})
response = request("POST", url, headers=headers, data=json_dumps(body)) json = log_and_parse_response( response, "Order creation response", )
if response.status_code != 200: raise ValidationError("Failed to create order")
return json
